+                        func_hash == PSTDEV_HASH or func_hash == VARIANCE_HASH or
+                        func_hash == PVARIANCE_HASH or func_hash == GEOMETRIC_MEAN_HASH or
+                        func_hash == HARMONIC_MEAN_HASH)
